@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms true .

@prefix geosrs: <https://w3id.org/geosrs/> .
@prefix geosrs_cs: <https://w3id.org/geosrs/cs#> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://w3id.org/example-data-srs#myAxis> ;
            sh:resultMessage "A coordinate system axis should have exactly one axis direction"@en ;
            sh:resultPath geosrs_cs:axisDirection ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:ClassConstraintComponent ;
            sh:sourceShape geosrs:CoordinateSystemAxis_axisDirection_Shape_Property ;
            sh:value geosrs_cs:North ] .

@prefix geosrs: <https://w3id.org/geosrs/> .
