[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://w3id.org/example-data-srs#ecsc> ;
            sh:resultMessage "A coordinate system should have at least one axis"@en ;
            sh:resultPath geosrs_cs:axis ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:ClassConstraintComponent ;
            sh:sourceShape geosrs:CoordinateSystem_axis_Shape_Property ;
            sh:value <https://w3id.org/example-data-srs#excsc_axis2> ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://w3id.org/example-data-srs#ecsc> ;
            sh:resultMessage "A coordinate system should have at least one axis"@en ;
            sh:resultPath geosrs_cs:axis ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:ClassConstraintComponent ;
            sh:sourceShape geosrs:CoordinateSystem_axis_Shape_Property ;
            sh:value <https://w3id.org/example-data-srs#ecsc_axis1> ] .

